VALUES
  ('diplomatic-adfe9b2d-moex-00648', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-110-c655adf3', 'sub-diplomatic-adfe9b2d-04', NULL, 'single_choice', '依司法院大法官解釋，若法律規定國家對宗教之監督僅適用於佛、道教，未對其他宗教為相同之限制，該 法律規定是否合憲？', '["違憲，因為宗教自由乃是不得以法律限制之基本權", "違憲，因為宗教自由之限制乃是內政部之行政保留事項", "違憲，因為違反宗教中立原則與宗教平等原則", "合憲，因為國家對宗教自由得以法律為必要之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:13+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00649', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-110-c655adf3', 'sub-diplomatic-adfe9b2d-04', NULL, 'single_choice', '關於憲法平等權，下列何者尚非司法院大法官解釋曾闡述之內涵？', '["對相同事物為差別待遇而無正當理由", "所採取分類與規範目的之達成間是否具一定關聯性", "是否以促進社會多元化為規範目的", "對於不同事物未為合理之差別待遇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:13+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00650', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-110-c655adf3', 'sub-diplomatic-adfe9b2d-04', NULL, 'single_choice', '下列何者不屬於訴訟權之保障範圍？', '["裁判應妥速進行，不得耗時過久", "訴訟費用不得過高，超出人民可得負擔之程度", "所有訴訟程序，均應採取三級三審制", "人民提起之行政訴訟，應得請求暫時權利保護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:13+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00651', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-110-c655adf3', 'sub-diplomatic-adfe9b2d-04', NULL, 'single_choice', '有關憲法未明文列舉之權利，下列敘述何者正確？', '["不受保障", "修憲後方得保障", "不妨害社會秩序公共利益者，受憲法保障", "不妨害國家主權者，受憲法保障"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:13+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00652', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-110-c655adf3', 'sub-diplomatic-adfe9b2d-04', NULL, 'single_choice', '依憲法規定及大法官解釋，人民基本權利之保障與限制，下列敘述何者錯誤？', '["憲法未明文列舉規定之自由權利的保障與限制，其依據為第22條及第23條", "基於人性尊嚴之理念，個人主體性及人格之自由發展，應受憲法保障", "凡憲法保障之基本權利，均僅得對國家主張", "憲法有明文列舉規定的基本權利之限制依據為憲法第23條"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:13+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00653', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-110-c655adf3', 'sub-diplomatic-adfe9b2d-04', NULL, 'single_choice', '依憲法或憲法增修條文規定，下列何者並非總統之職權？', '["全國陸海空軍之統帥權", "緊急命令發布權", "院際爭議調解權", "議決國家其他重要事項之權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:13+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00654', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-110-c655adf3', 'sub-diplomatic-adfe9b2d-04', NULL, 'single_choice', '關於行政院之財政權，下列敘述何者錯誤？', '["行政院於會計年度開始3個月前，應將下年度預算案提出於立法院", "行政院於會計年度結束後4個月內，應提出決算於監察院", "立法院對於行政院所提預算案，不得為增減支出之提議", "行政院對於司法院所提出之年度司法概算，不得刪減，但得加註意見"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:13+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00655', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-110-c655adf3', 'sub-diplomatic-adfe9b2d-04', NULL, 'single_choice', '關於立法權之敘述，下列何者正確？', '["立法院為國家最高立法機關，惟地方議會更具有在地性，因此中央法律不得與自治規章有所牴觸", "基於民主正當性，立法院得於每年集會前，要求總統進行國情報告", "立法院經總統解散後，在新選出的立法委員就職前，為求議事不中斷，會期應續行之", "立法委員不得兼任官吏，亦不得兼任公營事業機構之職務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:13+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
